35: // Helper functions to get the correct hostname for an L7 health check.
36: const std::string& HealthCheckerFactory::getHostname(const HostSharedPtr& host,
37:                                                      const std::string& config_hostname,
38:                                                      const ClusterInfoConstSharedPtr& cluster) {
39:   if (!host->hostnameForHealthChecks().empty()) {
40:     return host->hostnameForHealthChecks();
41:   }
42: 
43:   if (!config_hostname.empty()) {
44:     return config_hostname;
45:   }
46: 
47:   return cluster->name();
48: }
