94: absl::StatusOr<PayloadMatcher::MatchSegments> PayloadMatcher::loadProtoBytes(
95:     const Protobuf::RepeatedPtrField<envoy::config::core::v3::HealthCheck::Payload>& byte_array) {
96:   MatchSegments result;
97: 
98:   for (const auto& entry : byte_array) {
99:     std::vector<uint8_t> decoded;
100:     if (entry.has_text()) {
101:       decoded = Hex::decode(entry.text());
102:       if (decoded.empty()) {
103:         return absl::InvalidArgumentError(fmt::format("invalid hex string '{}'", entry.text()));
104:       }
105:     } else {
106:       decoded.assign(entry.binary().begin(), entry.binary().end());
107:     }
108:     if (!decoded.empty()) {
109:       result.push_back(decoded);
110:     }
111:   }
112: 
113:   return result;
114: }
